import{_ as n,o as e,c as s,a0 as t}from"./chunks/framework.CSK6mTG2.js";const h=JSON.parse('{"title":"在 Vue 中为什么不推荐用 index 做 key","description":"","frontmatter":{"title":"在 Vue 中为什么不推荐用 index 做 key","author":"唐超","date":"2021-12-12"},"headers":[],"relativePath":"menu1/在 Vue 中为什么不推荐用 index 做 key.md","filePath":"menu1/在 Vue 中为什么不推荐用 index 做 key.md"}'),p={name:"menu1/在 Vue 中为什么不推荐用 index 做 key.md"};function i(o,a,l,d,r,c){return e(),s("div",null,[...a[0]||(a[0]=[t(`<p>当 Vue.js 用 v-for 正在更新已渲染过的元素列表时，它默认用就地<strong>复用策略</strong></p><h4 id="用-index-作为-key-时-在对数据进行-逆序添加-逆序删除等破坏顺序的操作时-会全部更新。产生没必要的真实-dom更新-从而导致效率低" tabindex="-1">用 index 作为 key 时，在对数据进行，逆序添加，逆序删除等破坏顺序的操作时，会全部更新。产生没必要的真实 DOM更新，从而导致效率低 <a class="header-anchor" href="#用-index-作为-key-时-在对数据进行-逆序添加-逆序删除等破坏顺序的操作时-会全部更新。产生没必要的真实-dom更新-从而导致效率低" aria-label="Permalink to &quot;用 index 作为 key 时，在对数据进行，逆序添加，逆序删除等破坏顺序的操作时，会全部更新。产生没必要的真实 DOM更新，从而导致效率低&quot;">​</a></h4><h4 id="用-index-作为-key-时-如果结构中包含输入类的-dom-会产生错误的-dom-更新" tabindex="-1">用 index 作为 key 时，如果结构中包含输入类的 DOM，会产生错误的 DOM 更新 <a class="header-anchor" href="#用-index-作为-key-时-如果结构中包含输入类的-dom-会产生错误的-dom-更新" aria-label="Permalink to &quot;用 index 作为 key 时，如果结构中包含输入类的 DOM，会产生错误的 DOM 更新&quot;">​</a></h4><h4 id="在开发中最好每条数据使用唯一标识固定的数据作为-key-比如后台返回的-id-手机号-身份证号等唯一值" tabindex="-1">在开发中最好每条数据使用唯一标识固定的数据作为 key，比如后台返回的 ID，手机号，身份证号等唯一值 <a class="header-anchor" href="#在开发中最好每条数据使用唯一标识固定的数据作为-key-比如后台返回的-id-手机号-身份证号等唯一值" aria-label="Permalink to &quot;在开发中最好每条数据使用唯一标识固定的数据作为 key，比如后台返回的 ID，手机号，身份证号等唯一值&quot;">​</a></h4><h4 id="如果不存在对数据逆序添加-逆序删除等破坏顺序的操作时-仅用于渲染展示用时-使用-index-作为-key-也是可以的-但是还是不建议使用-养成良好开发习惯" tabindex="-1">如果不存在对数据逆序添加，逆序删除等破坏顺序的操作时，仅用于渲染展示用时，使用 index 作为 key 也是可以的（但是还是不建议使用，养成良好开发习惯） <a class="header-anchor" href="#如果不存在对数据逆序添加-逆序删除等破坏顺序的操作时-仅用于渲染展示用时-使用-index-作为-key-也是可以的-但是还是不建议使用-养成良好开发习惯" aria-label="Permalink to &quot;如果不存在对数据逆序添加，逆序删除等破坏顺序的操作时，仅用于渲染展示用时，使用 index 作为 key 也是可以的（但是还是不建议使用，养成良好开发习惯）&quot;">​</a></h4><p>为什么我没有复现大部分时候我们即使使用index作为key，不会复现这个问题，这好像与我们上述分析不符。但是事实上，“使用index作为key并且不会出问题”这种场景，其实过程是这样的：</p><h3 id="第一步-通过修改数据删除第一行-数据变化引起vue去更新视图-更新的过程中发现key相同-最终第一行保持不变-反而是第二行消失。这是第一次render。" tabindex="-1">第一步：通过修改数据删除第一行，数据变化引起vue去更新视图，更新的过程中发现key相同，最终第一行保持不变，反而是第二行消失。这是第一次render。 <a class="header-anchor" href="#第一步-通过修改数据删除第一行-数据变化引起vue去更新视图-更新的过程中发现key相同-最终第一行保持不变-反而是第二行消失。这是第一次render。" aria-label="Permalink to &quot;第一步：通过修改数据删除第一行，数据变化引起vue去更新视图，更新的过程中发现key相同，最终第一行保持不变，反而是第二行消失。这是第一次render。&quot;">​</a></h3><h3 id="第二步-第一行的virtualdom的确没有变-但是第一行的组件的props变了-由原来第一行的props-变成了第二行的props-由于props变化-第一行的组件需要使用新的props更新视图-最终第一行变成了第二行的样子。这是第二次render。" tabindex="-1">第二步：第一行的VirtualDOM的确没有变，但是第一行的组件的props变了，由原来第一行的props，变成了第二行的props，由于props变化，第一行的组件需要使用新的props更新视图，最终第一行变成了第二行的样子。这是第二次render。 <a class="header-anchor" href="#第二步-第一行的virtualdom的确没有变-但是第一行的组件的props变了-由原来第一行的props-变成了第二行的props-由于props变化-第一行的组件需要使用新的props更新视图-最终第一行变成了第二行的样子。这是第二次render。" aria-label="Permalink to &quot;第二步：第一行的VirtualDOM的确没有变，但是第一行的组件的props变了，由原来第一行的props，变成了第二行的props，由于props变化，第一行的组件需要使用新的props更新视图，最终第一行变成了第二行的样子。这是第二次render。&quot;">​</a></h3><p>也就是说，“使用index作为key并且不会出问题”这种场景，是因为render了两次，才最终达成了视图的正确更新。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    &lt;template v-if=&quot;switched&quot;&gt;</span></span>
<span class="line"><span>      &lt;p&gt;正常的例子：删除哪行，的确是删了哪行&lt;/p&gt;</span></span>
<span class="line"><span>      &lt;div v-for=&quot;(item, index) in data&quot; :key=&quot;index&quot;&gt;</span></span>
<span class="line"><span>        &lt;StateComponent :name=&quot;\`依赖于状态的属性+\${item.name}\`&quot;/&gt;</span></span>
<span class="line"><span>        &lt;button @click=&quot;handleDelete(index)&quot;&gt;删除这一行&lt;/button&gt;</span></span>
<span class="line"><span>      &lt;/div&gt;</span></span>
<span class="line"><span>    &lt;/template&gt;</span></span>
<span class="line"><span>    &lt;template v-else&gt;</span></span>
<span class="line"><span>      &lt;p&gt;异常的例子：删除哪行，不符合预期&lt;/p&gt;</span></span>
<span class="line"><span>      &lt;div v-for=&quot;(item, index) in data&quot; :key=&quot;index&quot;&gt;</span></span>
<span class="line"><span>        &lt;StaticComponent :name=&quot;\`不依赖于状态的属性\`&quot;/&gt;</span></span>
<span class="line"><span>        &lt;button @click=&quot;handleDelete(index)&quot;&gt;删除这一行&lt;/button&gt;</span></span>
<span class="line"><span>      &lt;/div&gt;</span></span>
<span class="line"><span>    &lt;/template&gt;</span></span></code></pre></div><p>不更新示例，checkbox被复用 <code>临时 DOM 状态 表单输入值</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;input type=&quot;text&quot; /&gt;</span></span>
<span class="line"><span>--------------------</span></span>
<span class="line"><span>      &lt;li v-for=&quot;(item, index) in list&quot; :key=&quot;index&quot;&gt;</span></span>
<span class="line"><span>        &lt;input type=&quot;checkbox&quot; name=&quot;&quot; id=&quot;&quot; /&gt;</span></span>
<span class="line"><span>        &lt;span&gt;item: {{ item }}&lt;/span&gt;</span></span>
<span class="line"><span>        &lt;button @click=&quot;deleteItem(index)&quot;&gt;删除&lt;/button&gt;</span></span>
<span class="line"><span>      &lt;/li&gt;</span></span></code></pre></div><p><code>依赖子组件状态</code> 子组件有自己的data数据，则这个数据不更新</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>子组件</span></span>
<span class="line"><span>&lt;div&gt;</span></span>
<span class="line"><span>  &lt;span&gt;{{ name }}&lt;/span&gt;</span></span>
<span class="line"><span>  count值为：{{ innerCount }}</span></span>
<span class="line"><span>  &lt;button @click=&quot;$emit(&#39;delete&#39;)&quot;&gt;-&lt;/button&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>data() {</span></span>
<span class="line"><span>  return {</span></span>
<span class="line"><span>    innerCount: this.count</span></span>
<span class="line"><span>  } </span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>innerCount这个数据不是props过来的，不是响应式</span></span></code></pre></div><h3 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h3><p>在使用非文本节点的组件，且这个组件没有依赖于响应式的props，那么此时对于列表的删除操作会导致视图错乱。 如果是文本节点 Vue的Diff过程对文本节点有特殊处理，不管key一不一样，都会用“新的文本节点”覆盖“旧的文本节点”。</p><p>写列表渲染时， <code>依赖子组件状态</code>或<code>临时 DOM 状态</code>的情况，如果有 删除、增加、排序这样的功能，不要把 index 作为 key。</p><h3 id="笔记2" tabindex="-1">笔记2 <a class="header-anchor" href="#笔记2" aria-label="Permalink to &quot;笔记2&quot;">​</a></h3><p>当我们修改了数据，数据的变动会触发订阅该数据变化的dom对象的更新，这个过程大致可分为三个阶段：</p><h4 id="_1首选是会重新构建虚拟dom树" tabindex="-1">1首选是会重新构建虚拟dom树 <a class="header-anchor" href="#_1首选是会重新构建虚拟dom树" aria-label="Permalink to &quot;1首选是会重新构建虚拟dom树&quot;">​</a></h4><h4 id="_2然后对比新旧虚拟dom树的节点-这里使用的就是大名鼎鼎的-differ-算法-也是这里要展开讲述的核心" tabindex="-1">2然后对比新旧虚拟dom树的节点,这里使用的就是大名鼎鼎的 differ 算法，也是这里要展开讲述的核心 <a class="header-anchor" href="#_2然后对比新旧虚拟dom树的节点-这里使用的就是大名鼎鼎的-differ-算法-也是这里要展开讲述的核心" aria-label="Permalink to &quot;2然后对比新旧虚拟dom树的节点,这里使用的就是大名鼎鼎的 differ 算法，也是这里要展开讲述的核心&quot;">​</a></h4><h4 id="_3根据对比结果-删除、添加、更新真实的dom节点。而非全部更新替换-这也就是虚拟dom的优势所在。" tabindex="-1">3根据对比结果，删除、添加、更新真实的dom节点。而非全部更新替换，这也就是虚拟dom的优势所在。 <a class="header-anchor" href="#_3根据对比结果-删除、添加、更新真实的dom节点。而非全部更新替换-这也就是虚拟dom的优势所在。" aria-label="Permalink to &quot;3根据对比结果，删除、添加、更新真实的dom节点。而非全部更新替换，这也就是虚拟dom的优势所在。&quot;">​</a></h4>`,22)])])}const m=n(p,[["render",i]]);export{h as __pageData,m as default};
